from flask import Flask, request, abort, send_file
import os

app = Flask(__name__)
BASE_DIR = "/app/files"

@app.route("/download")
def download():
    filename = request.args.get("file")
    if not filename:
        abort(400)
    # TODO: исправить Path Traversal
    path = filename
    if not os.path.exists(path):
        abort(404)
    return send_file(path)
